        template = Template('Name: {{ name }}<br>Email: {{ email }}<br>Inquiry: {{ inquiry }}', autoescape=False)
        return template.render(name=name, email=email, inquiry=inquiry)

    else:
        return render_template('index.html')

if __name__ == '__main__':
